package com.example.socialmediacampaignagentsprintboot.agent;import dev.langchain4j.service.MemoryId;import dev.langchain4j.service.UserMessage;import dev.langchain4j.service.V;/** * Represents a Copywriter AI Agent responsible for drafting and revising social media posts * based on strategic campaign objectives and feedback. *<p> * Key Responsibilities: * - Create initial drafts for posts by interpreting campaign context and adhering to *   predefined strategies. * - Rewrite drafts when rejected by quality assurance, or the human user when a rewrite request is thrown *   and by incorporating reviewer feedback to meet specified criteria while remaining aligned with the campaign context. *<p> * Methods: * - `writePost`: Generates the initial draft of a social media post based on the provided *   campaign context and strategy. * - `rewritePost`: Revises rejected drafts using feedback from reviewers and ensuring *   strict alignment with the original campaign context. */public interface CopywriterAgent {    @UserMessage("""        [BLACKBOARD CONTEXT]:        {{campaignContext}}                Directive:        Write the initial draft for this post based on the strategy in the context above.        """)    String writePost(@MemoryId String memoryId, @V("campaignContext") String campaignContext);    @UserMessage("""        The following draft you wrote was REJECTED by the quality assurance reviewer.        [BLACKBOARD CONTEXT]        {{campaignContext}}                [REJECTED DRAFT]:        {{previousDraft}}                [REVIEWER FEEDBACK]:        {{feedback}}        Please rewrite the post to fix these exact issues while strictly adhering to the Blackboard Context.        Remember our previous conversation history if applicable.        Return ONLY the new post text.        """)    String rewritePost(@MemoryId String memoryId,                       @V("campaignContext") String campaignContext,                       @V("previousDraft") String previousDraft,                       @V("feedback") String feedback);}